@page "/notifications"
@using BlazorNotifications.Services
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationService NotificationSvc

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@notifications.Count</span></h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    /// <summary>
    /// Runs during both SSR and interactive — loads initial data so it appears
    /// in the first server-rendered HTML without a second fetch on reconnect.
    /// </summary>
    protected override async Task OnInitializedAsync()
    {
        notifications = await NotificationSvc.GetNotificationsAsync();
        _lastSeenId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
    }

    /// <summary>
    /// Only fires once the component is interactive in the browser.
    /// Starts the polling loop here so it never runs during static SSR.
    /// </summary>
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(5));

        while (!ct.IsCancellationRequested)
        {
            try
            {
                // Wait for the next tick; will throw on cancellation
                if (!await timer.WaitForNextTickAsync(ct))
                    break;

                // Simulate an external notification arriving
                NotificationSvc.SimulateIncoming();

                // Fetch only new notifications since last seen
                var newOnes = await NotificationSvc.GetNotificationsSinceAsync(_lastSeenId);

                if (newOnes.Count > 0)
                {
                    notifications.AddRange(newOnes);
                    _lastSeenId = newOnes.Max(n => n.Id);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

